const performance = $('Get Performance Card').first().json;
const summary = $('Get Daily Summary').first().json;

const prompt = `Write a professional LinkedIn post about AI-powered Gold prediction. Data:

Performance (7d): ${JSON.stringify(performance, null, 2)}

Daily Summary: ${JSON.stringify(summary, null, 2)}

Tone: professional, thought-leadership. Focus on AI/ML methodology and how technology is transforming financial analysis. Include 3-5 relevant hashtags (#Gold #AI #FinTech #MachineLearning). 300-500 words. Mention Griffin Gold naturally. End with engagement question.`;

return [{ json: { prompt } }];

const response = $('Claude Generate').first().json;
const text = response.content[0].text.trim();
return [{ json: { text } }];

const text = $('Extract Post Text').first().json.text;
const now = new Date().toISOString();
console.log(`[${now}] LinkedIn post published: ${text.substring(0, 80)}...`);
return [{ json: { status: 'posted', platform: 'linkedin', timestamp: now, post_length: text.length } }];
